  1→use cupel::app::{
  2→    Backspace, Copy, CupelWorkspace, Cut, Delete, End, Home, Left, Paste, Quit, Right, SelectAll,
  3→    SelectLeft, SelectRight, ShowCharacterPalette, TextInput,
  4→};
  5→use gpui::{
  6→    App, AppContext, Application, Bounds, KeyBinding, WindowBounds, WindowOptions, px, size,
  7→};
  8→
  9→fn main() {
 10→    Application::new().run(|cx: &mut App| {
 11→        let bounds = Bounds::centered(None, size(px(300.), px(300.)), cx);
 12→        cx.bind_keys([
 13→            KeyBinding::new("backspace", Backspace, None),
 14→            KeyBinding::new("delete", Delete, None),
 15→            KeyBinding::new("left", Left, None),
 16→            KeyBinding::new("right", Right, None),
 17→            KeyBinding::new("shift-left", SelectLeft, None),
 18→            KeyBinding::new("shift-right", SelectRight, None),
 19→            KeyBinding::new("cmd-a", SelectAll, None),
 20→            KeyBinding::new("cmd-v", Paste, None),
 21→            KeyBinding::new("cmd-c", Copy, None),
 22→            KeyBinding::new("cmd-x", Cut, None),
 23→            KeyBinding::new("home", Home, None),
 24→            KeyBinding::new("end", End, None),
 25→            KeyBinding::new("ctrl-cmd-space", ShowCharacterPalette, None),
 26→        ]);
 27→        
 28→        let command_output = "Loading...".into();
 29→
 30→        let window = cx
 31→            .open_window(
 32→                WindowOptions {
 33→                    window_bounds: Some(WindowBounds::Windowed(bounds)),
 34→                    ..Default::default()
 35→                },
 36→                |_, cx| {
 37→                    let text_input = cx.new(|cx| TextInput {
 38→                        focus_handle: cx.focus_handle(),
 39→                        content: "".into(),
 40→                        placeholder: "Type here...".into(),
 41→                        selected_range: 0..0,
 42→                        selection_reversed: false,
 43→                        marked_range: None,
 44→                        last_layout: None,
 45→                        last_bounds: None,
 46→                        is_selecting: false,
 47→                    });
 48→                    cx.new(|cx| CupelWorkspace {
 49→                        text_input,
 50→                        recent_keystrokes: vec![],
 51→                        command_output,
 52→                        focus_handle: cx.focus_handle(),
 53→                    })
 54→                },
 55→            )
 56→            .expect("Expected text example.");
 57→        let view = window.update(cx, |_, _, cx| cx.entity()).expect("");
 58→
 59→        cx.spawn(async move |mut cx| {
 60→            let output = cx
 61→                .background_executor()
 62→                .spawn(async {
 63→                    let rt = tokio::runtime::Runtime::new().expect("tokio runtime");
 64→                    rt.block_on(async {
 65→                        tokio::process::Command::new("git")
 66→                            .arg("log")
 67→                            .arg("--oneline")
 68→                            .output()
 69→                            .await
 70→                    })
 71→                })
 72→                .await;
 73→
 74→            match output {
 75→                Ok(output) => {
 76→                    let text = String::from_utf8_lossy(&output.stdout).to_string();
 77→                    view.update(&mut cx, |view, cx| {
 78→                        view.command_output = text.into();
 79→                        cx.notify();
 80→                    })
 81→                    .ok();
 82→                }
 83→                Err(e) => {
 84→                    view.update(&mut cx, |view, cx| {
 85→                        view.command_output = format!("Error: {}", e).into();
 86→                        cx.notify();
 87→                    })
 88→                    .ok();
 89→                }
 90→            }
 91→        })
 92→        .detach();
 93→
 94→        cx.observe_keystrokes(move |ev, _, cx| {
 95→            view.update(cx, |view, cx| {
 96→                view.recent_keystrokes.push(ev.keystroke.clone());
 97→                cx.notify();
 98→            })
 99→        })
100→        .detach();
101→
102→        cx.on_keyboard_layout_change({
103→            move |cx| {
104→                window.update(cx, |_, _, cx| cx.notify()).ok();
105→            }
106→        })
107→        .detach();
108→
109→        window
110→            .update(cx, |view, window, cx| {
111→                window.focus(&view.text_input.read(cx).focus_handle);
112→                cx.activate(true);
113→            })
114→            .expect("");
115→        cx.on_action(|_: &Quit, cx| cx.quit());
116→        cx.bind_keys([KeyBinding::new("cmd-q", Quit, None)]);
117→    });
118→}
